import React from 'react'
import ReactApexChart from 'react-apexcharts'
import './styles.css'

const ApexChart = () => {
  const [state, setState] = React.useState({
    series: [
      {
        name: 'Temperature Anomaly',
        data: [-1.4, 2.6, -0.8, 3.4, -2.1, 1.9, 4.2, -1.6, 2.8, -3.2, 1.2, 3.9],
      },
    ],
    options: {
      chart: {
        height: 350,
        type: 'line',
        zoom: {
          enabled: false,
        },
      },
      dataLabels: {
        enabled: false,
      },
      title: {
        text: 'Monthly Temperature Anomaly',
        align: 'left',
      },
      subtitle: {
        text: 'Months below the baseline draw in a different color',
        align: 'left',
      },
      yaxis: {
        labels: {
          formatter: function (val) {
            return val.toFixed(1) + '°C'
          },
        },
      },
      xaxis: {
        categories: [
          'Jan',
          'Feb',
          'Mar',
          'Apr',
          'May',
          'Jun',
          'Jul',
          'Aug',
          'Sep',
          'Oct',
          'Nov',
          'Dec',
        ],
      },
      stroke: {
        width: 5,
        curve: 'monotoneCubic',
      },
      plotOptions: {
        line: {
          colors: {
            threshold: 0,
            colorAboveThreshold: '#008FFB',
            colorBelowThreshold: '#FF4560',
          },
        },
      },
    },
  })

  return (
    <div>
      <div id="chart">
        <ReactApexChart
          options={state.options}
          series={state.series}
          type="line"
          height={350}
        />
      </div>
    </div>
  )
}

export default ApexChart
